  1→/**
  2→ * Native Text Classifier
  3→ * Supports both MiniLM embeddings (via TextEmbeddingsModule) and TF-IDF
  4→ */
  5→
  6→import {
  7→  ALL_MINILM_L6_V2,
  8→  TextEmbeddingsModule,
  9→} from "react-native-executorch";
 10→import { classifyWithEmbeddings, type LabelEmbedding } from "./embeddings";
 11→import type {
 12→  ClassificationMethod,
 13→  ClassificationResult,
 14→  TagSuggestion,
 15→} from "./index.d";
 16→import {
 17→  ALL_CATEGORY_KEYS,
 18→  ALL_CUISINE_KEYS,
 19→  ALL_SEASON_KEYS,
 20→  CATEGORY_LABELS,
 21→  CUISINE_LABELS,
 22→  SEASON_LABELS,
 23→} from "./labels";
 24→import { classifyWithTfIdf } from "./tfidf";
 25→import { extractTitle } from "./title-extractor";
 26→
 27→/**
 28→ * Singleton pattern for model and label embeddings
 29→ */
 30→class EmbeddingsManager {
 31→  private static instance: TextEmbeddingsModule | null = null;
 32→  private static labelEmbeddings: Array<LabelEmbedding> | null = null;
 33→  private static isInitializing = false;
 34→
 35→  static async initialize(): Promise<void> {
 36→    if (this.instance && this.labelEmbeddings) {
 37→      return; // Already initialized
 38→    }
 39→
 40→    if (this.isInitializing) {
 41→      // Wait for ongoing initialization
 42→      await new Promise((resolve) => setTimeout(resolve, 100));
 43→      return this.initialize();
 44→    }
 45→
 46→    this.isInitializing = true;
 47→
 48→    try {
 49→      console.log("[Text Classifier] Initializing MiniLM model...");
 50→
 51→      // Create and load the model
 52→      this.instance = new TextEmbeddingsModule();
 53→      await this.instance.load({
 54→        modelSource: ALL_MINILM_L6_V2.modelSource,
 55→        tokenizerSource: ALL_MINILM_L6_V2.tokenizerSource,
 56→      });
 57→
 58→      console.log("[Text Classifier] Computing label embeddings...");
 59→
 60→      // Compute embeddings for all labels
 61→      const embeddings: Array<LabelEmbedding> = [];
 62→
 63→      for (const key of ALL_SEASON_KEYS) {
 64→        const description = SEASON_LABELS[key];
 65→        const embeddingRaw = await this.instance.forward(description);
 66→        const embedding = Array.from(embeddingRaw);
 67→        embeddings.push({ key, category: "season", embedding });
 68→      }
 69→
 70→      for (const key of ALL_CUISINE_KEYS) {
 71→        const description = CUISINE_LABELS[key];
 72→        const embeddingRaw = await this.instance.forward(description);
 73→        const embedding = Array.from(embeddingRaw);
 74→        embeddings.push({ key, category: "cuisine", embedding });
 75→      }
 76→
 77→      for (const key of ALL_CATEGORY_KEYS) {
 78→        const description = CATEGORY_LABELS[key];
 79→        const embeddingRaw = await this.instance.forward(description);
 80→        const embedding = Array.from(embeddingRaw);
 81→        embeddings.push({ key, category: "food-category", embedding });
 82→      }
 83→
 84→      this.labelEmbeddings = embeddings;
 85→      console.log(
 86→        `[Text Classifier] Initialized with ${embeddings.length} label embeddings`
 87→      );
 88→    } finally {
 89→      this.isInitializing = false;
 90→    }
 91→  }
 92→
 93→  static async classify(text: string): Promise<Array<TagSuggestion>> {
 94→    await this.initialize();
 95→
 96→    if (!this.instance || !this.labelEmbeddings) {
 97→      throw new Error("Failed to initialize embeddings");
 98→    }
 99→
100→    // Get text embedding
101→    const textEmbeddingRaw = await this.instance.forward(text);
102→    const textEmbedding = Array.from(textEmbeddingRaw);
103→
104→    // Use shared classification function
105→    return classifyWithEmbeddings(textEmbedding, this.labelEmbeddings);
106→  }
107→}
108→
109→/**
110→ * Classify text using TF-IDF scoring
111→ */
112→function classifyWithTfIdfMethod(text: string): ClassificationResult {
113→  const startTime = Date.now();
114→
115→  try {
116→    const title = extractTitle(text);
117→    const allSuggestions = classifyWithTfIdf(text);
118→
119→    // Filter to top suggestions (max 2 per category with confidence >= 0.3)
120→    const suggestions: Array<TagSuggestion> = [];
121→    const counts = { season: 0, cuisine: 0, "food-category": 0 };
122→
123→    for (const suggestion of allSuggestions) {
124→      if (counts[suggestion.category] < 2 && suggestion.confidence >= 0.3) {
125→        suggestions.push(suggestion);
126→        counts[suggestion.category]++;
127→      }
128→    }
129→
130→    return {
131→      title,
132→      suggestions,
133→      processingTimeMs: Date.now() - startTime,
134→    };
135→  } catch (error) {
136→    console.error("[Text Classifier] TF-IDF classification failed:", error);
137→    return {
138→      title: extractTitle(text),
139→      suggestions: [],
140→      processingTimeMs: Date.now() - startTime,
141→    };
142→  }
143→}
144→
145→/**
146→ * Classify text using embeddings
147→ */
148→async function classifyWithEmbeddingsMethod(
149→  text: string
150→): Promise<ClassificationResult> {
151→  const startTime = Date.now();
152→
153→  try {
154→    const title = extractTitle(text);
155→    const allSuggestions = await EmbeddingsManager.classify(text);
156→
157→    // Sort by confidence
158→    allSuggestions.sort((a, b) => b.confidence - a.confidence);
159→
160→    // Filter to top suggestions (max 2 per category)
161→    const suggestions: Array<TagSuggestion> = [];
162→    const counts = { season: 0, cuisine: 0, "food-category": 0 };
163→
164→    for (const suggestion of allSuggestions) {
165→      if (counts[suggestion.category] < 2) {
166→        suggestions.push(suggestion);
167→        counts[suggestion.category]++;
168→      }
169→    }
170→
171→    console.log(
172→      `[Text Classifier] Found ${suggestions.length} suggestions in ${
173→        Date.now() - startTime
174→      }ms`
175→    );
176→
177→    return {
178→      title,
179→      suggestions,
180→      processingTimeMs: Date.now() - startTime,
181→    };
182→  } catch (error) {
183→    console.error("[Text Classifier] Embeddings classification failed:", error);
184→    return {
185→      title: extractTitle(text),
186→      suggestions: [],
187→      processingTimeMs: Date.now() - startTime,
188→    };
189→  }
