  5→
  6→import type { AppLanguage } from "@/lib/types/language";
  7→import type { DataUrl } from "@/lib/types/primitives";
  8→import { createWorker, type Worker } from "tesseract.js";
  9→import type { OcrResult } from "./types";
 10→
 11→const TESSERACT_LANG_MAP: Record<AppLanguage, string> = {
 12→  en: "eng",
 13→  pl: "pol",
 14→};
 15→
 16→// Persistent worker instance for reuse across multiple extractions
 17→let worker: Worker | null = null;
 18→let currentWorkerLang: string | null = null;
 19→
 20→/**
 21→ * Extract text from an image using Tesseract.js OCR
 22→ * @param imageUri - Data URL of the image to process
 23→ * @param language - Language for OCR recognition
 24→ * @returns OCR result with extracted text blocks and confidence
 25→ */
 26→export async function extractText(imageUri: DataUrl, language: AppLanguage = "en"): Promise<OcrResult> {
 27→  try {
 28→    const tessLang = TESSERACT_LANG_MAP[language];
 29→    console.log(`[OCR Bridge] Starting text extraction (web/tesseract, lang=${tessLang})`);
 30→
 31→    // Reinitialize worker if language changed
 32→    if (worker && currentWorkerLang !== tessLang) {
 33→      console.log(`[OCR Bridge] Language changed from ${currentWorkerLang} to ${tessLang}, reinitializing worker`);
 34→      await worker.terminate();
 35→      worker = null;
 36→      currentWorkerLang = null;
 37→    }
 38→
 39→    // Lazy initialization: create worker on first use
 40→    if (!worker) {
 41→      console.log(`[OCR Bridge] Initializing Tesseract worker for ${tessLang}`);
 42→      try {
 43→        worker = await createWorker(tessLang, 1, {
 44→          errorHandler: (err) =>
 45→            console.error("[OCR Bridge] Worker error:", err),
 46→        });
 47→        currentWorkerLang = tessLang;
 48→        console.log("[OCR Bridge] Tesseract worker ready");
 49→      } catch (workerError) {
 50→        console.error(
 51→          "[OCR Bridge] Failed to create Tesseract worker:",
 52→          workerError
 53→        );
 54→        return {
 55→          success: false,
 56→          error: `Worker initialization failed: ${
 57→            workerError instanceof Error ? workerError.message : "Unknown error"
 58→          }`,
 59→        };
 60→      }
 61→    }
 62→
 63→    // Perform OCR recognition
 64→    const { data } = await worker.recognize(imageUri);
 65→
 66→    if (!data.text || data.text.trim().length === 0) {
 67→      console.log("[OCR Bridge] No text detected in image");
 68→      return {
 69→        success: true,
 70→        text: "",
 71→        textBlocks: [],
 72→        confidence: 0,
 73→      };
 74→    }
 75→
 76→    // Extract text blocks from Tesseract result
 77→    const textBlocks = data.blocks
 78→      ?.map((block) => block.text)
 79→      .filter((text) => text.trim()) ?? [data.text];
 80→
 81→    // Normalize confidence from 0-100 to 0-1
 82→    const confidence = data.confidence / 100;
 83→
 84→    console.log(
 85→      `[OCR Bridge] Text extraction complete: ${textBlocks.length} blocks, ${
 86→        data.text.length
 87→      } characters, ${Math.round(confidence * 100)}% confidence`
 88→    );
 89→
 90→    return {
 91→      success: true,
 92→      text: data.text,
 93→      textBlocks,
 94→      confidence,
 95→    };
 96→  } catch (error) {
 97→    console.error("[OCR Bridge] Text extraction failed:", error);
 98→    return {
 99→      success: false,
100→      error: error instanceof Error ? error.message : "Unknown error",
101→    };
102→  }
103→}
104→
105→/**
106→ * Terminate the Tesseract worker
107→ * Call this when OCR is no longer needed to free resources
108→ */
109→export async function terminateWorker(): Promise<void> {
110→  if (worker) {
111→    await worker.terminate();
112→    worker = null;
113→    console.log("[OCR Bridge] Tesseract worker terminated");
114→  }
115→}
